      "n": 3,
      "column": "left",
      "text": "No ta Spohschuma wiꞥſch-\nPreekschâ ſchkehlahs wiꞥſch\nadebbesis/ ar Kruffu un deg-\nchahnu Ohglehm.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Tas KUNGS likke\nhrkonus ribbeht no Debbes/\ntas Wiſſu-augstakajs iſlaide\nvu Behrkonu/ Kruffu un deg-\nchas Ohgles.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Un wiꞥſch mette fauvas\nultas/ un iſkaitija tohs/ un\niroja Sibbitus/ un iſtruh-\naja tohs.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Un Ubdens Dselmesrah.\nahs/ un tahs Pasaules Dib-\nai tappe apklahti no tawas\nmmaſchanas ak KUNGS!\nPuhſchanas tahs Dwachas\nwn Nahthu.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Wiꞥſch fuhtija no tahs\nagstibas/ un nehme manni/\ninsch uſwike manni no leeſem\ndenim.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Wiꞥſch atpestija manni\nmanna ſtipra Eenaidneeka/\nno manneem Nihdetajeem/\ntee jo warrent bija/ ne ka es.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Kas manni pahrwarreja\nannu Behdu Laikâ/ bet tas\nUNGS bija mans Patwe-\nms.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un wiꞥſch iſwedde man-\nPlattumâ/ wiꞥſch israhwe\nanni/ jo wiꞥſam bija labs\nrahts pee manni.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Tas KUNGS atmakk-\nan pehz mannas Taifnibas/\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Jo es fargu ta KUNGA\nZettus/ un ne eſinn besdeewigtturrejees prett mannu Deewu.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Jo wiﬀas wiſka Teefas\nirr manna Preekschâ/ un wiſka\nLiffunius es ne leeſu no mannim\nnohſt.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Bet es eﬁnu beswainigs\npreeksch wiſna/ un fargohs no\nGrehkeim.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un tas KUNGS dohſ\nman atkah pehz mannas Taifni-\nbas/ pehz mannu Rohku Schki-\nstibas preeksch win na Azzim.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Pee teem Swehteemeſſi\ntn fwehts/ un pee teem Sirde-\nSkaidreen eſſi tu skaidrs.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Pee teem Schkihsteemeſſi\ntn schkihsts/ un pee teem Pahr-\nwehrtiteem eſſi tu pahrwehrtihts.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Jo tu atpesti tohs behdi-\ngus Laudis/ un tahs gresnas\nAzzis tu paſemmo.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Jo tu apgaifno mannu\nSpihdekli/ tas KUNGS mans\nDeews darra mannu Tumsibu\ngaſchu.\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Jo ar tewi warru es Kar-\nrogus fadansiht/ un ar mannu\nDeewu warru es pahr Muhrf\nlehkt.\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Ta STIPRA DEE-\nWA Zettch irr beswainigs/ ta\nKUNGA Walloca irr schkihta/\nwiſch irr par preeſchturra-\nmahin Bruzznahin wiﬀeem/ kas\nus wiſnu pataujahs.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Jo kur irr tahos Deews/\nppppp\n"
    }
  ],
  "confidence": "high",
